fn parse_count(value: &str) -> Result<usize> {
  let count = value.parse::<usize>()?;
  Ok(count)
}

match event.code {
  KeyCode::Enter => app.begin_current(),
  KeyCode::Esc => app.quit = true,
  _ => {}
}

fn visit_mut_call_expr(&mut self, call: &mut CallExpr) {
  call.visit_mut_children_with(self);
  if is_target_call(call) {
    self.found = true;
  }
}

pub fn resolve_specifier(specifier: &str) -> Result<ModuleSpecifier> {
  let url = ModuleSpecifier::parse(specifier)?;
  Ok(url)
}

async fn handler(State(state): State<AppState>) -> Json<Vec<Todo>> {
  let todos = state.todos.lock().await.clone();
  Json(todos)
}

fn should_ignore(path: &Path) -> bool {
  path.file_name()
    .and_then(|name| name.to_str())
    .map(|name| name.starts_with('.'))
    .unwrap_or(false)
}

